var colors = ['#5470c6', '#91cc75', '#fac858'];
var series = [
  {
    type: 'custom',
    coordinateSystem: 'none',
    renderItem: function(params, api) {
      var s = transformedData.sets[params.dataIndex];
      var cx = api.getWidth() / 2;
      var cy = api.getHeight() / 2 + 20;
      return {
        type: 'group',
        children: [
          {
            type: 'circle',
            shape: { cx: cx + s.x, cy: cy + s.y, r: s.r },
            style: {
              fill: colors[params.dataIndex % 3],
              opacity: 0.35,
              stroke: colors[params.dataIndex % 3],
              lineWidth: 2
            }
          },
          {
            type: 'text',
            style: {
              text: String(s.name) + '\n(' + String(s.size) + ')',
              x: cx + s.label_x,
              y: cy + s.label_y,
              textAlign: 'center',
              textVerticalAlign: 'middle',
              fill: '#333',
              font: 'bold 14px sans-serif'
            }
          }
        ]
      };
    },
    data: transformedData.sets
  },
  {
    type: 'custom',
    coordinateSystem: 'none',
    renderItem: function(params, api) {
      var inter = transformedData.intersections[params.dataIndex];
      var cx = api.getWidth() / 2;
      var cy = api.getHeight() / 2 + 20;
      return {
        type: 'text',
        style: {
          text: String(inter.size),
          x: cx + inter.x,
          y: cy + inter.y,
          textAlign: 'center',
          textVerticalAlign: 'middle',
          fill: '#000',
          font: 'bold 12px sans-serif'
        }
      };
    },
    data: transformedData.intersections
  }
];
option = {
  title: { text: 'User Segments (Euler/Venn)', left: 'center' },
  tooltip: {
    trigger: 'item',
    formatter: function(info) {
      var dataItem = info.seriesIndex === 0 ? transformedData.sets[info.dataIndex] : transformedData.intersections[info.dataIndex];
      var name = String(dataItem.name);
      var safeName = name.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
      return safeName + ': ' + dataItem.size;
    }
  },
  series: series
};
